# Financial calculator for NPV, IRR, and payback period
# Input: _query should be a JSON string with parameters
import json

# Parse the input query
try:
    params = json.loads(_query)
except:
    return "Error: Input must be valid JSON with cash_flows, discount_rate, and initial_investment"

cash_flows = params.get('cash_flows', [])
discount_rate = params.get('discount_rate', 0.1)
initial_investment = params.get('initial_investment', 0)

# Calculate NPV (Net Present Value)
def calculate_npv(cash_flows, discount_rate, initial_investment):
    npv = -initial_investment
    for i, cf in enumerate(cash_flows):
        npv += cf / ((1 + discount_rate) ** (i + 1))
    return npv

# Calculate Payback Period
def calculate_payback_period(cash_flows, initial_investment):
    cumulative = 0
    for i, cf in enumerate(cash_flows):
        cumulative += cf
        if cumulative >= initial_investment:
            return i + 1 - (cumulative - initial_investment) / cf
    return None

# Calculate IRR (simplified Newton-Raphson method)
def calculate_irr(cash_flows, initial_investment, iterations=100):
    rate = 0.1
    for _ in range(iterations):
        npv = -initial_investment
        npv_derivative = 0
        for i, cf in enumerate(cash_flows):
            period = i + 1
            npv += cf / ((1 + rate) ** period)
            npv_derivative -= period * cf / ((1 + rate) ** (period + 1))
        if abs(npv) < 0.01:
            return rate
        if npv_derivative != 0:
            rate = rate - npv / npv_derivative
    return rate

npv = calculate_npv(cash_flows, discount_rate, initial_investment)
payback = calculate_payback_period(cash_flows, initial_investment)
irr = calculate_irr(cash_flows, initial_investment)

result = {
    "npv": round(npv, 2),
    "irr": round(irr * 100, 2) if irr else None,
    "payback_period_years": round(payback, 2) if payback else "Not achieved",
    "discount_rate": discount_rate * 100
}

return json.dumps(result)
